INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (1, 122511, 7, 0, "ずいぶんと色々なものが流れているね。\nここがプールでないなら、\n魚が潜んでいそうだけど…", 1, 943, 11, 0, 0, 19430025);
INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES ("", 0, "", "", "", "", 943, 91, "", "", 19430026);
